CREATE TABLE `news` (
  `id_news` int(12) NOT NULL,
  `id_user` int(12) NOT NULL COMMENT 'ID 锌芯谢褜蟹芯胁邪褌械谢褟, 褋芯蟹写邪胁褕械谐芯 薪芯胁芯褋褌褜',
  `title` varchar(120) NOT NULL COMMENT '袟邪谐芯谢芯胁芯泻 薪芯胁芯褋褌懈',
  `date` date NOT NULL COMMENT '袛邪褌邪 褋芯蟹写邪薪懈褟 薪芯胁芯褋褌懈',
  `text` text NOT NULL COMMENT '孝械泻褋褌 薪芯胁芯褋褌懈'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- 袛邪屑锌 写邪薪薪褘褏 褌邪斜谢懈褑褘 `news`
--

INSERT INTO `news` (`id_news`, `id_user`, `title`, `date`, `text`) VALUES
(7, 1, '孝械褋褌芯胁邪褟 薪芯胁芯褋褌褜 1', '2025-03-30', '<p>孝械泻褋褌 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 1.</p>\r\n\r\n<p>袙褌芯褉芯泄 邪斜蟹邪褑 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 1.</p>'),
(8, 1, '孝械褋褌芯胁邪褟 薪芯胁芯褋褌褜 2', '2025-03-30', '<p>孝械泻褋褌 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 2.</p>\r\n\r\n<p>袙褌芯褉芯泄 邪斜蟹邪褑 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 2.</p>'),
(9, 1, '孝械褋褌芯胁邪褟 薪芯胁芯褋褌褜 3', '2025-03-30', '<p>孝械泻褋褌 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 3.</p>\r\n\r\n<p>袙褌芯褉芯泄 邪斜蟹邪褑 褌械褋褌芯胁芯泄 薪芯胁芯褋褌懈 3.</p>'),
(14, 1, '袘芯谢褜褕邪褟 褌械泻褋褌芯胁邪褟 薪芯胁芯褋褌褜', '2025-04-04', '<p>袘芯谢褜褕邪褟 褌械泻褋褌芯胁邪褟 薪芯胁芯褋褌褜.</p>\r\n\r\n<p>携 褋械褉褜褢蟹薪芯, 褝褌芯 芯褔械薪褜 斜芯谢褜褕邪褟 褌械泻褋褌芯胁邪褟 薪芯胁芯褋褌褜.</p>\r\n\r\n<p>袛邪卸械 薪械 锌褘褌邪泄褋褟 械褢 褔懈褌邪褌褜, 褌褘 褍屑褉褢褕褜 芯褌 褋褌邪褉芯褋褌懈! 袠谢懈 芯褌 褋锌懈写邪. 袠谢懈 芯褌 斜褉褞褕薪芯谐芯 褌懈褎邪.</p>\r\n\r\n<p>啸胁邪褌懈褌 褔懈褌邪褌褜! 效懈褌邪褌褜 胁褉械写薪芯 写谢褟 褌褍锌褘褏, 胁写褉褍谐 芯薪懈 锌芯褍屑薪械褞褌!</p>\r\n<p>袨褋褌邪薪芯胁懈褋褜...</p>\r\n\r\n<p><b>You don\'t puss me!</p>\r\n\r\n<p>Press F to respect! Press F to respect! Press F to respect!</b></p>'),
(15, 1, '孝械谐懈', '2025-04-04', '<p>孝械泻褋褌</p>\r\n<h3>袟邪谐芯谢芯胁芯泻 褌褉械褌褜械谐芯 褍褉芯胁薪褟</h3>\r\n<p><b>袞懈褉薪褘泄 褌械泻褋褌!</b> 袩褉褟屑 泻邪泻 褌褘.</p>');

